import subprocess
import pytest

def calc(expr):
    result = subprocess.run(
        ["python3", "calc.py", expr],
        capture_output=True, text=True, timeout=5
    )
    return result.stdout.strip()

def test_addition():
    assert calc("2+3") == "5"

def test_subtraction():
    assert calc("10-3") == "7"

def test_multiplication():
    assert calc("4*5") == "20"

def test_division():
    assert calc("10/4") == "2.5"

def test_power():
    assert calc("2**3") == "8"

def test_grouping():
    assert calc("(1+2)*3") == "9"

def test_nested_groups():
    assert calc("((2+3)*2)+1") == "11"

def test_sqrt():
    assert calc("sqrt(16)") == "4.0"

def test_abs():
    assert calc("abs(-5)") == "5"

def test_variable():
    assert calc("x=5; x*2+3") == "13"

def test_multiple_vars():
    assert calc("x=3; y=4; x+y") == "7"

def test_division_by_zero():
    result = calc("1/0")
    assert result.startswith("Error:")

def test_undefined_var():
    result = calc("x+1")
    assert result.startswith("Error:")

def test_integer_output():
    # Results that are whole numbers should show as ints
    assert calc("2+3") == "5"
    assert calc("6/2") == "3.0" or calc("6/2") == "3"
